1	/* ============================================
2	   习惯管理 - 天子日课
3	   ============================================ */
4	
5	/* ---- 页面头部 ---- */
6	.page-header {
7	  display: flex;
8	  justify-content: space-between;
9	  align-items: flex-start;
10	  margin-bottom: var(--space-xl);
11	}
12	
13	.add-btn {
14	  width: 72rpx;
15	  height: 72rpx;
16	  border-radius: var(--radius-full);
17	  background: var(--color-accent);
18	  color: var(--color-text-inverse);
19	  display: flex;
20	  align-items: center;
21	  justify-content: center;
22	  font-size: 44rpx;
23	  font-weight: 300;
24	  line-height: 1;
25	  transition: opacity 0.2s;
26	}
27	
28	.add-btn:active {
29	  opacity: 0.8;
30	}
31	
32	/* ---- 分类管理入口 ---- */
33	.domain-manager-entry {
34	  padding: var(--space-md) 0;
35	  margin-bottom: var(--space-xs);
36	  color: var(--color-accent);
37	  font-size: var(--text-sm);
38	  display: flex;
39	  align-items: center;
40	  opacity: 0.8;
41	}
42	
43	.domain-manager-entry:active {
44	  opacity: 1;
45	}
46	
47	/* ---- 领域标题 ---- */
48	.domain-title {
49	  display: block;
50	  font-size: var(--text-sm);
51	  color: var(--color-text-muted);
52	  margin: var(--space-xl) 0 var(--space-md);
53	  padding-left: var(--space-md);
54	  border-left: 3rpx solid var(--color-accent);
55	}
56	
57	/* ---- 习惯卡片 ---- */
58	.habit-card {
59	  background: var(--color-card);
60	  border: 1rpx solid var(--color-border);
61	  border-radius: var(--radius-md);
62	  padding: var(--space-lg);
63	  margin-bottom: var(--space-sm);
64	  transition: all 0.2s ease;
65	}
66	
67	.habit-card.inactive {
68	  opacity: 0.45;
69	}
70	
71	.habit-info {
72	  margin-bottom: var(--space-md);
73	}
74	
75	.habit-name {
76	  display: block;
77	  font-size: var(--text-md);
78	  font-weight: 500;
79	  color: var(--color-text-primary);
80	  letter-spacing: 0.02em;
81	}
82	
83	.habit-desc {
84	  display: block;
85	  font-size: var(--text-xs);
86	  color: var(--color-text-muted);
87	  margin-top: var(--space-xs);
88	}
89	
90	.habit-meta {
91	  display: block;
92	  font-size: var(--text-xs);
93	  color: var(--color-text-muted);
94	  margin-top: var(--space-sm);
95	  font-feature-settings: "tnum";
96	}
97	
98	/* ---- 卡片操作按钮 ---- */
99	.habit-actions {
100	  display: flex;
101	  gap: var(--space-sm);
102	}
103	
104	.habit-actions .action-btn {
105	  padding: var(--space-xs) var(--space-md);
106	  border-radius: var(--radius-xs);
107	  font-size: var(--text-xs);
108	  font-weight: 500;
109	  background: var(--color-surface);
110	  color: var(--color-text-secondary);
111	  border: 1rpx solid var(--color-border);
112	  transition: all 0.2s;
113	}
114	
115	.habit-actions .action-btn:active {
116	  background: var(--color-border);
117	}
118	
119	.habit-actions .action-btn.danger {
120	  background: var(--color-danger-subtle);
121	  color: var(--color-danger);
122	  border-color: transparent;
123	}
124	
125	.habit-actions .action-btn.danger:active {
126	  opacity: 0.8;
127	}
128	
129	.habit-actions .action-btn.disabled {
130	  opacity: 0.4;
131	}
132	
133	/* ---- 分类弹窗 ---- */
134	.modal-header-row {
135	  display: flex;
136	  justify-content: space-between;
137	  align-items: center;
138	  margin-bottom: var(--space-xl);
139	}
140	
141	.modal-header-row .modal-title {
142	  margin-bottom: 0;
143	}
144	
145	.modal-add-btn {
146	  font-size: var(--text-md);
147	  color: var(--color-accent);
148	  font-weight: 500;
149	}
150	
151	.domain-list-item {
152	  display: flex;
153	  align-items: center;
154	  gap: var(--space-md);
155	  padding: var(--space-lg) 0;
156	  border-bottom: 1rpx solid var(--color-border);
157	}
158	
159	.domain-list-item.system {
160	  opacity: 0.55;
161	}
162	
163	.domain-list-item:last-child {
164	  border-bottom: none;
165	}
166	
167	.domain-list-icon {
168	  font-size: 36rpx;
169	  flex-shrink: 0;
170	  line-height: 1;
171	}
172	
173	.domain-list-name {
174	  flex: 1;
175	  font-size: var(--text-md);
176	  color: var(--color-text-primary);
177	}
178	
179	.domain-list-tag {
180	  font-size: var(--text-xs);
181	  color: var(--color-text-muted);
182	  flex-shrink: 0;
183	}
184	
185	.domain-list-actions {
186	  display: flex;
187	  gap: var(--space-sm);
188	  flex-shrink: 0;
189	}
190	
191	.domain-list-btn {
192	  font-size: var(--text-xs);
193	  padding: var(--space-xs) var(--space-md);
194	  border-radius: var(--radius-xs);
195	  background: var(--color-surface);
196	  color: var(--color-text-secondary);
197	  border: 1rpx solid var(--color-border);
198	}
199	
200	.domain-list-btn.danger {
201	  background: var(--color-danger-subtle);
202	  color: var(--color-danger);
203	  border-color: transparent;
204	}
205	
206	.domain-list-btn.disabled {
207	  opacity: 0.4;
208	}
209	
210	/* ---- Emoji 选择器 ---- */
211	.emoji-grid {
212	  display: flex;
213	  flex-wrap: wrap;
214	  gap: var(--space-sm);
215	}
216	
217	.emoji-item {
218	  width: calc((100% - 24rpx) / 3);
219	  text-align: center;
220	  padding: var(--space-md) 0;
221	  font-size: 44rpx;
222	  border-radius: var(--radius-sm);
223	  background: var(--color-surface);
224	  border: 1rpx solid var(--color-border);
225	  box-sizing: border-box;
226	  transition: all 0.2s;
227	}
228	
229	.emoji-item:active {
230	  border-color: var(--color-accent);
231	}
232	
233	.emoji-item.selected {
234	  background: var(--color-accent-subtle);
235	  border-color: var(--color-accent);
236	}
237	
238	/* ---- 颜色选择器 ---- */
239	.color-picker {
240	  display: flex;
241	  gap: var(--space-md);
242	  flex-wrap: wrap;
243	}
244	
245	.color-item {
246	  width: 56rpx;
247	  height: 56rpx;
248	  border-radius: var(--radius-full);
249	  border: 3rpx solid transparent;
250	  box-sizing: border-box;
251	  transition: all 0.2s;
252	}
253	
254	.color-item:active {
255	  transform: scale(1.1);
256	}
257	
258	.color-item.selected {
259	  border-color: var(--color-accent);
260	  box-shadow: 0 0 0 2rpx var(--color-accent-subtle);
261	}
