1	import { useState } from "react";
2	import { View, Text, Input, Picker } from "@tarojs/components";
3	import { useDidShow, showModal, showToast } from "@tarojs/taro";
4	import { apiFetch } from "../../lib";
5	import { getDomains, saveDomains, Domain, UNCATEGORIZED } from "../../lib/domains";
6	import "./index.scss";
7	
8	const EMOJI_OPTIONS = [
9	  "💪", "📚", "✨", "💼", "🧠", "🏛️", "🌍", "🏠",
10	  "🎯", "🎨", "🎵", "✍️", "🧘", "🏃", "🍎", "💻",
11	  "📝", "🎬", "🗣️", "🧭", "🔬", "📊", "💡", "⭐",
12	];
13	
14	const COLOR_OPTIONS = [
15	  "#ef4444", "#3b82f6", "#ec4899", "#f59e0b",
16	  "#8b5cf6", "#10b981", "#06b6d4", "#78716c",
17	];
18	
19	interface Habit {
20	  id: string;
21	  title: string;
22	  description: string | null;
23	  domainId: string;
24	  unit: string;
25	  targetValue: number;
26	  frequency: string;
27	  isActive: boolean;
28	}
29	
30	export default function HabitsPage() {
31	  const [habits, setHabits] = useState<Habit[]>([]);
32	  const [loading, setLoading] = useState(true);
33	  const [showForm, setShowForm] = useState(false);
34	  const [editId, setEditId] = useState<string | null>(null);
35	  const [form, setForm] = useState({
36	    title: "", description: "", domainIdx: 0, unit: "次",
37	    targetValue: 1, frequency: "daily",
38	  });
39	
40	  // Domain management state
41	  const [showDomainManager, setShowDomainManager] = useState(false);
42	  const [domainManagerView, setDomainManagerView] = useState<"list" | "new" | "edit">("list");
43	  const [domainForm, setDomainForm] = useState<Domain>({ name: "", icon: "💪", color: "#ef4444" });
44	  const [editingDomainName, setEditingDomainName] = useState<string | null>(null);
45	  const [saving, setSaving] = useState(false);
46	
47	  useDidShow(() => { fetchHabits(); });
48	
49	  async function fetchHabits() {
50	    try {
51	      setHabits(await apiFetch("/api/habits"));
52	    } catch {
53	      showToast({ title: "获取习惯列表失败", icon: "none" });
54	    }
55	    setLoading(false);
56	  }
57	
58	  function openNew() {
59	    setEditId(null);
60	    setForm({ title: "", description: "", domainIdx: 0, unit: "次", targetValue: 1, frequency: "daily" });
61	    setShowForm(true);
62	  }
63	
64	  function openEdit(h: Habit) {
65	    setEditId(h.id);
66	    const domains = getDomains();
67	    const idx = domains.findIndex(d => d.name === h.domainId);
68	    setForm({
69	      title: h.title,
70	      description: h.description || "",
71	      domainIdx: idx >= 0 ? idx : domains.length - 1,
72	      unit: h.unit,
73	      targetValue: h.targetValue,
74	      frequency: h.frequency,
75	    });
76	    setShowForm(true);
77	  }
78	
79	  async function handleSave() {
80	    const domains = getDomains();
81	    if (form.domainIdx < 0 || form.domainIdx >= domains.length) {
82	      showToast({ title: "领域索引无效", icon: "none" });
83	      return;
84	    }
85	    setSaving(true);
86	    try {
87	      const body = { ...form, domainId: domains[form.domainIdx].name };
88	      if (editId) {
89	        await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: editId, ...body }) });
90	      } else {
91	        await apiFetch("/api/habits", { method: "POST", body: JSON.stringify(body) });
92	      }
93	      setShowForm(false);
94	      fetchHabits();
95	    } catch {
96	      showToast({ title: "保存习惯失败", icon: "none" });
97	    } finally {
98	      setSaving(false);
99	    }
100	  }
101	
102	  async function deleteHabit(id: string) {
103	    try {
104	      await apiFetch("/api/habits", { method: "DELETE", body: JSON.stringify({ id }) });
105	      fetchHabits();
106	    } catch {
107	      showToast({ title: "删除习惯失败", icon: "none" });
108	    }
109	  }
110	
111	  async function toggleActive(id: string, current: boolean) {
112	    try {
113	      await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id, isActive: !current }) });
114	      fetchHabits();
115	    } catch {
116	      showToast({ title: "操作失败", icon: "none" });
117	    }
118	  }
119	
120	  // ---- Domain management handlers ----
121	
122	  function openDomainManager() {
123	    setShowForm(false);
124	    setDomainManagerView("list");
125	    setDomainForm({ name: "", icon: "💪", color: "#ef4444" });
126	    setEditingDomainName(null);
127	    setShowDomainManager(true);
128	  }
129	
130	  function openNewDomain() {
131	    setDomainForm({ name: "", icon: "💪", color: "#ef4444" });
132	    setDomainManagerView("new");
133	  }
134	
135	  function openEditDomain(domain: Domain) {
136	    setEditingDomainName(domain.name);
137	    setDomainForm({ name: domain.name, icon: domain.icon, color: domain.color });
138	    setDomainManagerView("edit");
139	  }
140	
141	  async function handleDomainSave() {
142	    const name = domainForm.name.trim();
143	    if (!name) return;
144	
145	    const userDomains = getDomains().filter(d => d.name !== UNCATEGORIZED.name);
146	
147	    if (domainManagerView === "new") {
148	      if (userDomains.some(d => d.name === name)) {
149	        showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
150	        return;
151	      }
152	      userDomains.push({ name, icon: domainForm.icon, color: domainForm.color });
153	    } else if (domainManagerView === "edit") {
154	      const idx = userDomains.findIndex(d => d.name === editingDomainName);
155	      if (idx === -1) return;
156	
157	      if (name !== editingDomainName && userDomains.some(d => d.name === name)) {
158	        showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
159	        return;
160	      }
161	
162	      const oldName = userDomains[idx].name;
163	      userDomains[idx] = { name, icon: domainForm.icon, color: domainForm.color };
164	
165	      // If domain renamed, update all habits under old name
166	      if (name !== oldName) {
167	        try {
168	          for (const h of habits.filter(h => h.domainId === oldName)) {
169	            await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: h.id, domainId: name }) });
170	          }
171	          fetchHabits();
172	        } catch {
173	          showToast({ title: "迁移习惯失败", icon: "none" });
174	          return;
175	        }
176	      }
177	    }
178	
179	    saveDomains(userDomains);
180	    setDomainManagerView("list");
181	    setEditingDomainName(null);
182	  }
183	
184	  async function handleDeleteDomain(domain: Domain) {
185	    const count = habits.filter(h => h.domainId === domain.name).length;
186	    const res = await showModal({
187	      title: "删除领域",
188	      content: `确定删除"${domain.name}"吗？其下 ${count} 个习惯将移入"未分类"。`,
189	    });
190	
191	    if (!res.confirm) return;
192	
193	    setSaving(true);
194	    try {
195	      // Move habits to 未分类 first, then delete domain
196	      for (const h of habits.filter(h => h.domainId === domain.name)) {
197	        await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: h.id, domainId: UNCATEGORIZED.name }) });
198	      }
199	
200	      const userDomains = getDomains()
201	        .filter(d => d.name !== UNCATEGORIZED.name && d.name !== domain.name);
202	      saveDomains(userDomains);
203	
204	      fetchHabits();
205	    } catch {
206	      showToast({ title: "删除领域失败", icon: "none" });
207	    } finally {
208	      setSaving(false);
209	    }
210	  }
211	
212	  const domains = getDomains();
213	
214	  return (
215	    <View className="page">
216	      <View className="page-header">
217	        <View>
218	          <Text className="page-title">习惯管理</Text>
219	          <Text className="page-subtitle">管理你的每日修炼清单</Text>
220	        </View>
221	        <View className="add-btn" onClick={openNew}><Text>+</Text></View>
222	      </View>
223	
224	      <View className="domain-manager-entry" onClick={openDomainManager}>
225	        <Text>管理分类</Text>
226	      </View>
227	
228	      {domains.map((domain) => {
229	        const domainHabits = habits.filter((h) => h.domainId === domain.name);
230	        return (
231	          <View key={domain.name}>
232	            <Text className="domain-title">{domain.icon} {domain.name}</Text>
233	            {domainHabits.map((habit) => (
234	              <View key={habit.id} className={`habit-card ${!habit.isActive ? "inactive" : ""}`}>
235	                <View className="habit-info">
236	                  <Text className="habit-name">{habit.title}</Text>
237	                  {habit.description && <Text className="habit-desc">{habit.description}</Text>}
238	                  <View className="habit-meta">
239	                    <Text>{habit.frequency === "daily" ? "每日" : habit.frequency}</Text>
240	                    <Text> · </Text>
241	                    <Text>目标 {habit.targetValue}{habit.unit}</Text>
242	                  </View>
243	                </View>
244	                <View className="habit-actions">
245	                  <Text className={`action-btn ${saving ? "disabled" : ""}`} onClick={() => !saving && toggleActive(habit.id, habit.isActive)}>
246	                    {habit.isActive ? "停用" : "启用"}
247	                  </Text>
248	                  <Text className="action-btn" onClick={() => openEdit(habit)}>编辑</Text>
249	                  <Text className={`action-btn danger ${saving ? "disabled" : ""}`} onClick={() => !saving && deleteHabit(habit.id)}>删除</Text>
250	                </View>
251	              </View>
252	            ))}
253	          </View>
254	        );
255	      })}
256	
257	      {!loading && habits.length === 0 && (
258	        <View className="empty"><Text>还没有习惯，点右上角 + 开始</Text></View>
259	      )}
260	
261	      {/* ---- Habit Form Modal ---- */}
262	      {showForm && (
263	        <View className="modal-mask" onClick={() => setShowForm(false)}>
264	          <View className="modal" onClick={(e) => e.stopPropagation()}>
265	            <Text className="modal-title">{editId ? "编辑习惯" : "新增习惯"}</Text>
266	
267	            <View className="form-group">
268	              <Text className="form-label">名称</Text>
269	              <Input className="form-input" placeholder="如：晨跑30分钟" value={form.title} onInput={(e) => setForm({ ...form, title: e.detail.value })} />
270	            </View>
271	
272	            <View className="form-group">
273	              <Text className="form-label">描述</Text>
274	              <Input className="form-input" placeholder="具体怎么做" value={form.description} onInput={(e) => setForm({ ...form, description: e.detail.value })} />
275	            </View>
276	
277	            <View className="form-row">
278	              <View className="form-group flex-1">
279	                <Text className="form-label">领域</Text>
280	                <Picker mode="selector" range={domains.map(d => d.icon + " " + d.name)} value={form.domainIdx} onChange={(e) => setForm({ ...form, domainIdx: +e.detail.value })}>
281	                  <View className="form-picker">{domains[form.domainIdx].icon} {domains[form.domainIdx].name}</View>
282	                </Picker>
283	              </View>
284	              <View className="form-group flex-1">
285	                <Text className="form-label">频率</Text>
286	                <Picker mode="selector" range={["每日", "每周", "工作日"]} value={form.frequency === "daily" ? 0 : form.frequency === "weekly" ? 1 : 2} onChange={(e) => setForm({ ...form, frequency: ["daily", "weekly", "weekday"][+e.detail.value] })}>
287	                  <View className="form-picker">{form.frequency === "daily" ? "每日" : form.frequency === "weekly" ? "每周" : "工作日"}</View>
288	                </Picker>
289	              </View>
290	            </View>
291	
292	            <View className="form-row">
293	              <View className="form-group flex-1">
294	                <Text className="form-label">目标值</Text>
295	                <Input className="form-input" type="number" value={String(form.targetValue)} onInput={(e) => setForm({ ...form, targetValue: +e.detail.value || 1 })} />
296	              </View>
297	              <View className="form-group flex-1">
298	                <Text className="form-label">单位</Text>
299	                <Input className="form-input" placeholder="次/分钟/页" value={form.unit} onInput={(e) => setForm({ ...form, unit: e.detail.value })} />
300	              </View>
301	            </View>
302	
303	            <View className="form-buttons">
304	              <View className="btn-cancel" onClick={() => setShowForm(false)}><Text>取消</Text></View>
305	              <View className={"btn-save" + (saving ? " disabled" : "")} onClick={() => !saving && handleSave()}><Text>{editId ? "保存" : "添加"}</Text></View>
306	            </View>
307	          </View>
308	        </View>
309	      )}
310	
311	      {/* ---- Domain Manager Modal ---- */}
312	      {showDomainManager && (
313	        <View className="modal-mask" onClick={() => setShowDomainManager(false)}>
314	          <View className="modal" onClick={(e) => e.stopPropagation()}>
315	
316	            {/* List View */}
317	            {domainManagerView === "list" && (
318	              <>
319	                <View className="modal-header-row">
320	                  <Text className="modal-title">管理分类</Text>
321	                  <Text className="modal-add-btn" onClick={openNewDomain}>+ 新增</Text>
322	                </View>
323	
324	                {domains.map((domain) => {
325	                  const isSystem = domain.name === UNCATEGORIZED.name;
326	                  return (
327	                    <View key={domain.name} className={`domain-list-item ${isSystem ? "system" : ""}`}>
328	                      <Text className="domain-list-icon" style={{ color: domain.color }}>{domain.icon}</Text>
329	                      <Text className="domain-list-name">{domain.name}</Text>
330	                      {isSystem ? (
331	                        <Text className="domain-list-tag">系统内置</Text>
332	                      ) : (
333	                        <View className="domain-list-actions">
334	                          <Text className="domain-list-btn" onClick={() => openEditDomain(domain)}>编辑</Text>
335	                          <Text className={"domain-list-btn danger" + (saving ? " disabled" : "")} onClick={() => !saving && handleDeleteDomain(domain)}>删除</Text>
336	                        </View>
337	                      )}
338	                    </View>
339	                  );
340	                })}
341	
342	                <View className="form-buttons">
343	                  <View className="btn-cancel" onClick={() => setShowDomainManager(false)}><Text>关闭</Text></View>
344	                </View>
345	              </>
346	            )}
