382	                      <View
383	                        key={color}
384	                        className={`color-item ${domainForm.color === color ? "selected" : ""}`}
385	                        style={{ backgroundColor: color }}
386	                        onClick={() => setDomainForm({ ...domainForm, color })}
387	                      />
388	                    ))}
389	                  </View>
390	                </View>
391	
392	                <View className="form-buttons">
393	                  <View className="btn-cancel" onClick={() => setDomainManagerView("list")}><Text>取消</Text></View>
